#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[0] - y[0];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **points = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            points[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &points[i][0], &points[i][1]);
        }
        qsort(points, N, sizeof(int *), compare);
        int *dp = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            dp[i] = 1;
            for (int j = 0; j < i; j++) {
                if (points[i][1] <= points[j][1] + (points[i][0] - points[j][0]) * (points[j][1] - points[j-1][1]) / (points[j][0] - points[j-1][0])) {
                    dp[i] = (dp[i] > dp[j] + 1) ? dp[i] : dp[j] + 1;
                }
            }
        }
        int max = 0;
        for (int i = 0; i < N; i++) {
            if (dp[i] > max) {
                max = dp[i];
            }
        }
        printf("%d\n", max);
        free(dp);
        for (int i = 0; i < N; i++) {
            free(points[i]);
        }
        free(points);
    }
    return 0;
}

code.C++:
#include <iostream>
#include <algorithm>
using namespace std;

struct Point {
    int x, y;
};

bool compare(Point a, Point b) {
    return a.x < b.x;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Point *points = new Point[N];
        for (int i = 0; i < N; i++) {
            cin >> points[i].x >> points[i].y;
        }
        sort(points, points + N, compare);
        int *dp = new int[N];
        for (int i = 0; i < N; i++) {
            dp[i] = 1;
            for (int j = 0; j < i; j++) {
                if (points[i].y <= points[j].y + (points[i].x - points[j].x) * (points[j].y - points[j-1].y) / (points[j].x - points[j-1].x)) {
                    dp[i] = max(dp[i], dp[j] + 1);
                }
            }
        }
        int max = 0;
        for (int i = 0; i < N; i++) {
            if (dp[i] > max) {
                max = dp[i];
            }
        }
        cout << max << endl;
        delete[] dp;
        delete[] points;
    }
    return 0;
}

