function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let points = [];
    for (let i = 0; i < N; i++) {
        points.push(nextIntArray());
    }
    points.sort((a, b) => a[0] - b[0]);
    let dp = new Array(N).fill(1);
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < i; j++) {
            if (points[i][1] <= points[j][1] + (points[i][0] - points[j][0]) * (points[j][1] - points[j-1][1]) / (points[j][0] - points[j-1][0])) {
                dp[i] = Math.max(dp[i], dp[j] + 1);
            }
        }
    }
    console.log(Math.max(...dp));
}

